fn resolve_actions(
    model: &mut StepModel,
    aid: ActionId,
    attrs: &[Attribute],
    idmap: &BTreeMap<u64, AnyId>,
) -> Result<(), String> {
    let chosen_method_v = {
        let a = req(attrs, 2, "ACTION.chosen_method")?;
        ((|| -> Result<ActionMethodRef, String> {
            Ok(ActionMethodRef::from_any(
                *idmap
                    .get(&as_ref_id(a, "ACTION.chosen_method")?)
                    .ok_or_else(|| format!("ACTION.chosen_method: dangling ref"))?,
            )
            .map_err(|e| format!("ACTION.chosen_method: {e}"))?)
        })())?
    };
    let it = &mut model.actions.items[aid.0];
    it.chosen_method = chosen_method_v;
    Ok(())
}

fn resolve_action_assignments(
    model: &mut StepModel,
    aid: ActionAssignmentId,
    attrs: &[Attribute],
    idmap: &BTreeMap<u64, AnyId>,
) -> Result<(), String> {
    let assigned_action_v = {
        let a = req(attrs, 0, "ACTION_ASSIGNMENT.assigned_action")?;
        ((|| -> Result<ActionRef, String> {
            Ok(ActionRef::from_any(
                *idmap
                    .get(&as_ref_id(a, "ACTION_ASSIGNMENT.assigned_action")?)
                    .ok_or_else(|| format!("ACTION_ASSIGNMENT.assigned_action: dangling ref"))?,
            )
            .map_err(|e| format!("ACTION_ASSIGNMENT.assigned_action: {e}"))?)
        })())?
    };
    let it = &mut model.action_assignments.items[aid.0];
    it.assigned_action = assigned_action_v;
    Ok(())
}

fn resolve_action_directives(
    model: &mut StepModel,
    aid: ActionDirectiveId,
    attrs: &[Attribute],
    idmap: &BTreeMap<u64, AnyId>,
) -> Result<(), String> {
    let requests_v = {
        let a = req(attrs, 4, "ACTION_DIRECTIVE.requests")?;
        (match a {
            Attribute::List(l) => l
                .iter()
                .map(|e| {
                    (|| -> Result<VersionedActionRequestRef, String> {
                        Ok(VersionedActionRequestRef::from_any(
                            *idmap
                                .get(&as_ref_id(e, "ACTION_DIRECTIVE.requests")?)
                                .ok_or_else(|| {
                                    format!("ACTION_DIRECTIVE.requests: dangling ref")
                                })?,
                        )
                        .map_err(|e| format!("ACTION_DIRECTIVE.requests: {e}"))?)
                    })()
                })
                .collect::<Result<Vec<_>, String>>(),
            o => Err(format!(
                "ACTION_DIRECTIVE.requests: expected ref list, got {o:?}"
            )),
        })?
    };
    let it = &mut model.action_directives.items[aid.0];
    it.requests = requests_v;
    Ok(())
}

fn resolve_action_method_relationships(
    model: &mut StepModel,
    aid: ActionMethodRelationshipId,
    attrs: &[Attribute],
    idmap: &BTreeMap<u64, AnyId>,
) -> Result<(), String> {
    let relating_method_v = {
        let a = req(attrs, 2, "ACTION_METHOD_RELATIONSHIP.relating_method")?;
        ((|| -> Result<ActionMethodRef, String> {
            Ok(ActionMethodRef::from_any(
                *idmap
                    .get(&as_ref_id(a, "ACTION_METHOD_RELATIONSHIP.relating_method")?)
                    .ok_or_else(|| {
                        format!("ACTION_METHOD_RELATIONSHIP.relating_method: dangling ref")
                    })?,
            )
            .map_err(|e| format!("ACTION_METHOD_RELATIONSHIP.relating_method: {e}"))?)
        })())?
    };
    let related_method_v = {
        let a = req(attrs, 3, "ACTION_METHOD_RELATIONSHIP.related_method")?;
        ((|| -> Result<ActionMethodRef, String> {
            Ok(ActionMethodRef::from_any(
                *idmap
                    .get(&as_ref_id(a, "ACTION_METHOD_RELATIONSHIP.related_method")?)
                    .ok_or_else(|| {
                        format!("ACTION_METHOD_RELATIONSHIP.related_method: dangling ref")
                    })?,
            )
            .map_err(|e| format!("ACTION_METHOD_RELATIONSHIP.related_method: {e}"))?)
        })())?
    };
    let it = &mut model.action_method_relationships.items[aid.0];
    it.relating_method = relating_method_v;
    it.related_method = related_method_v;
    Ok(())
}

