fn resolve_general_datum_references(
    model: &mut StepModel,
    aid: GeneralDatumReferenceId,
    attrs: &[Attribute],
    idmap: &BTreeMap<u64, AnyId>,
) -> Result<(), String> {
    let of_shape_v = {
        let a = req(attrs, 2, "GENERAL_DATUM_REFERENCE.of_shape")?;
        ((|| -> Result<ProductDefinitionShapeRef, String> {
            Ok(ProductDefinitionShapeRef::from_any(
                *idmap
                    .get(&as_ref_id(a, "GENERAL_DATUM_REFERENCE.of_shape")?)
                    .ok_or_else(|| format!("GENERAL_DATUM_REFERENCE.of_shape: dangling ref"))?,
            )
            .map_err(|e| format!("GENERAL_DATUM_REFERENCE.of_shape: {e}"))?)
        })())?
    };
    let base_v = {
        let a = req(attrs, 4, "GENERAL_DATUM_REFERENCE.base")?;
        ((|| -> Result<DatumOrCommonDatumRef, String> {
            Ok(match a {
                Attribute::Typed { type_name, value } if type_name == "COMMON_DATUM_LIST" => {
                    DatumOrCommonDatumRef::CommonDatumList(match value.as_ref() {
                        Attribute::List(l) => l
                            .iter()
                            .map(|e| {
                                DatumReferenceElementRef::from_any(
                                    *idmap
                                        .get(&as_ref_id(e, "GENERAL_DATUM_REFERENCE.base")?)
                                        .ok_or_else(|| {
                                            format!("GENERAL_DATUM_REFERENCE.base: dangling ref")
                                        })?,
                                )
                            })
                            .collect::<Result<Vec<_>, String>>()?,
                        o => {
                            return Err(format!(
                                "GENERAL_DATUM_REFERENCE.base: agg list COMMON_DATUM_LIST: {o:?}"
                            ));
                        }
                    })
                }
                _ => DatumOrCommonDatumRef::from_any(
                    *idmap
                        .get(&as_ref_id(a, "GENERAL_DATUM_REFERENCE.base")?)
                        .ok_or_else(|| format!("GENERAL_DATUM_REFERENCE.base: dangling ref"))?,
                )
                .map_err(|e| format!("GENERAL_DATUM_REFERENCE.base: {e}"))?,
            })
        })())?
    };
    let modifiers_v = {
        let a = req(attrs, 5, "GENERAL_DATUM_REFERENCE.modifiers")?;
        match a { Attribute::Unset => None, _ => Some((match a { Attribute::List(l) => l.iter().map(|e| (|| -> Result<DatumReferenceModifierRef, String> { Ok(match e { Attribute::Typed { type_name, value } if type_name == "SIMPLE_DATUM_REFERENCE_MODIFIER" => DatumReferenceModifierRef::SimpleDatumReferenceModifier(match value.as_ref() { Attribute::Enum(s) => SimpleDatumReferenceModifier::parse(s).ok_or_else(|| format!("GENERAL_DATUM_REFERENCE.modifiers: bad enum SIMPLE_DATUM_REFERENCE_MODIFIER {s:?}"))?, o => return Err(format!("GENERAL_DATUM_REFERENCE.modifiers: enum SIMPLE_DATUM_REFERENCE_MODIFIER: {o:?}")) }), _ => DatumReferenceModifierRef::from_any(*idmap.get(&as_ref_id(e, "GENERAL_DATUM_REFERENCE.modifiers")?).ok_or_else(|| format!("GENERAL_DATUM_REFERENCE.modifiers: dangling ref"))?).map_err(|e| format!("GENERAL_DATUM_REFERENCE.modifiers: {e}"))? }) })()).collect::<Result<Vec<_>, String>>(), o => Err(format!("GENERAL_DATUM_REFERENCE.modifiers: expected ref list, got {o:?}")) })?) }
    };
    let it = &mut model.general_datum_references.items[aid.0];
    it.of_shape = of_shape_v;
    it.base = base_v;
    it.modifiers = modifiers_v;
    Ok(())
}

