fn resolve_point_styles(
    model: &mut StepModel,
    aid: PointStyleId,
    attrs: &[Attribute],
    idmap: &BTreeMap<u64, AnyId>,
) -> Result<(), String> {
    let marker_v = {
        let a = req(attrs, 1, "POINT_STYLE.marker")?;
        match a {
            Attribute::Unset => None,
            _ => Some(
                ((|| -> Result<MarkerSelectRef, String> {
                    Ok(match a {
                        Attribute::Typed { type_name, value } if type_name == "MARKER_TYPE" => {
                            MarkerSelectRef::MarkerType(match value.as_ref() {
                                Attribute::Enum(s) => MarkerType::parse(s).ok_or_else(|| {
                                    format!("POINT_STYLE.marker: bad enum MARKER_TYPE {s:?}")
                                })?,
                                o => {
                                    return Err(format!(
                                        "POINT_STYLE.marker: enum MARKER_TYPE: {o:?}"
                                    ));
                                }
                            })
                        }
                        _ => MarkerSelectRef::from_any(
                            *idmap
                                .get(&as_ref_id(a, "POINT_STYLE.marker")?)
                                .ok_or_else(|| format!("POINT_STYLE.marker: dangling ref"))?,
                        )
                        .map_err(|e| format!("POINT_STYLE.marker: {e}"))?,
                    })
                })())?,
            ),
        }
    };
    let marker_size_v = {
        let a = req(attrs, 2, "POINT_STYLE.marker_size")?;
        match a {
            Attribute::Unset => None,
            _ => Some(
                ((|| -> Result<SizeSelectRef, String> {
                    Ok(match a {
                        Attribute::Typed { type_name, .. }
                            if type_name == "DESCRIPTIVE_MEASURE" =>
                        {
                            SizeSelectRef::DescriptiveMeasure(
                                read_string_select(a, "POINT_STYLE.marker_size")?.value,
                            )
                        }
                        Attribute::Typed { type_name, .. }
                            if type_name == "POSITIVE_LENGTH_MEASURE" =>
                        {
                            SizeSelectRef::PositiveLengthMeasure(
                                read_measure_value(a, "POINT_STYLE.marker_size")?
                                    .value
                                    .as_f64(),
                            )
                        }
                        _ => SizeSelectRef::from_any(
                            *idmap
                                .get(&as_ref_id(a, "POINT_STYLE.marker_size")?)
                                .ok_or_else(|| format!("POINT_STYLE.marker_size: dangling ref"))?,
                        )
                        .map_err(|e| format!("POINT_STYLE.marker_size: {e}"))?,
                    })
                })())?,
            ),
        }
    };
    let marker_colour_v = {
        let a = req(attrs, 3, "POINT_STYLE.marker_colour")?;
        match a {
            Attribute::Unset => None,
            _ => Some(
                ((|| -> Result<ColourRef, String> {
                    Ok(ColourRef::from_any(
                        *idmap
                            .get(&as_ref_id(a, "POINT_STYLE.marker_colour")?)
                            .ok_or_else(|| format!("POINT_STYLE.marker_colour: dangling ref"))?,
                    )
                    .map_err(|e| format!("POINT_STYLE.marker_colour: {e}"))?)
                })())?,
            ),
        }
    };
    let it = &mut model.point_styles.items[aid.0];
    it.marker = marker_v;
    it.marker_size = marker_size_v;
    it.marker_colour = marker_colour_v;
    Ok(())
}

